int open_device(struct device *dev)
{
	int err;

	err = device_lock(dev);
	if (err)
		return err;

	err = device_power_on(dev);
	if (err)
		goto out_unlock;

	err = device_init(dev);
	if (err)
		goto out_power_off;

	return 0;

out_power_off:
	device_power_off(dev);
out_unlock:
	device_unlock(dev);
	return err;
}
